   116|
   117|// ---------------------------------------------------------------------------
   118|// Supabase config resolver
   119|// ---------------------------------------------------------------------------
   120|
   121|type SupabaseConfig = { url: string; key: string; missing: string[] };
   122|
   123|function resolveSupabase(): SupabaseConfig {
   124|  const url = (process.env.EXPO_PUBLIC_SUPABASE_URL || '').trim().replace(/\/+$/, '');
   125|  const key = (process.env.SUPABASE_SERVICE_ROLE_KEY || process.env.SUPABASE_SERVICE_KEY || '').trim();
   126|  const missing: string[] = [];
   127|  if (!url) missing.push('EXPO_PUBLIC_SUPABASE_URL');
   128|  if (!key) missing.push('SUPABASE_SERVICE_ROLE_KEY');
   129|  return { url, key, missing };
   130|}
   131|
   132|// ---------------------------------------------------------------------------
   133|// Table snapshot helpers
   134|// ---------------------------------------------------------------------------
   135|
   136|type TableSnapshotResult = {
   137|  table: string;
   138|  ok: boolean;
   139|  rowCount: number;
   140|  /** SHA-256 of the serialized JSON rows. */
   141|  hash: string | null;
   142|  /** Number of bytes on disk. */
   143|  bytes: number;
   144|  status: number;
   145|  error: string | null;
   146|  /** ISO timestamp. */
   147|  capturedAt: string;
   148|};
   149|
   150|async function fetchAllRows(
   151|  baseUrl: string,
   152|  key: string,
   153|  table: string,
   154|): Promise<{ rows: unknown[]; status: number; error: string | null }> {
   155|  const headers = {
   156|    apikey: key,
   157|    Authorization: `Bearer ${key}`,
   158|    Accept: 'application/json',
   159|  };
   160|
   161|  try {
   162|    // Fetch up to 50,000 rows per table. For visitor analytics tables that
   163|    // could have 27k+ events, we page with Range headers.
   164|    const allRows: unknown[] = [];
   165|    let offset = 0;
   166|    const pageSize = 1000;
   167|    const maxPages = 50; // 50,000 rows max
   168|
   169|    for (let page = 0; page < maxPages; page++) {
   170|      const controller = new AbortController();
   171|      const timeout = setTimeout(() => controller.abort(), 15_000);
   172|      try {
   173|        const res = await fetch(
   174|          `${baseUrl}/rest/v1/${table}?select=*&order=id.asc&limit=${pageSize}&offset=${offset}`,
   175|          {
   176|            method: 'GET',
   177|            signal: controller.signal,
   178|            headers: {
   179|              ...headers,
   180|              Range: `${offset}-${offset + pageSize - 1}`,
   181|              Prefer: 'count=exact',
   182|            },
   183|          },
   184|        );
   185|        clearTimeout(timeout);
   186|
   187|        if (res.status === 404) {
   188|          return { rows: [], status: 404, error: 'TABLE_NOT_FOUND' };
   189|        }
   190|        if (!res.ok) {
   191|          return { rows: [], status: res.status, error: `HTTP_${res.status}` };
   192|        }
   193|
   194|        const rows = (await res.json()) as unknown[];
   195|        allRows.push(...rows);
   196|
   197|        // If we got fewer rows than the page size, we've reached the end.
   198|        if (rows.length < pageSize) break;
   199|        offset += pageSize;
   200|      } catch (err) {
   201|        clearTimeout(timeout);
   202|        throw err;
   203|      }
   204|    }
   205|
   206|    return { rows: allRows, status: 200, error: null };
   207|  } catch (err) {
   208|    return {
   209|      rows: [],
   210|      status: 0,
   211|      error: err instanceof Error ? err.message : 'network_error',
   212|    };
   213|  }
   214|}
   215|
   216|function sha256OfJson(data: unknown): string {
   217|  const json = JSON.stringify(data);
   218|  return createHash('sha256').update(json).digest('hex');
   219|}
   220|
   221|async function snapshotOneTable(
   222|  baseUrl: string,
   223|  key: string,
   224|  table: string,
   225|  snapshotDir: string,
   226|): Promise<TableSnapshotResult> {
   227|  const capturedAt = new Date().toISOString();
   228|  const result = await fetchAllRows(baseUrl, key, table);
   229|
   230|  if (result.error === 'TABLE_NOT_FOUND') {
   231|    return {
   232|      table,
   233|      ok: false,
   234|      rowCount: 0,
   235|      hash: null,
   236|      bytes: 0,
   237|      status: 404,
   238|      error: 'TABLE_NOT_FOUND',
   239|      capturedAt,
   240|    };
   241|  }
   242|
   243|  if (result.error) {
   244|    return {
   245|      table,
   246|      ok: false,
   247|      rowCount: 0,
   248|      hash: null,
   249|      bytes: 0,
   250|      status: result.status,
   251|      error: result.error,
   252|      capturedAt,
   253|    };
   254|  }
   255|
   256|  // Write the rows to disk.
   257|  const json = JSON.stringify(result.rows, null, 2);
   258|  const hash = createHash('sha256').update(json).digest('hex');
   259|  const filePath = path.join(snapshotDir, `${table}.json`);
   260|
   261|  try {
   262|    await fs.writeFile(filePath, json, 'utf8');
   263|  } catch (err) {
   264|    return {
   265|      table,
   266|      ok: false,
   267|      rowCount: result.rows.length,
   268|      hash,
   269|      bytes: json.length,
   270|      status: 200,
   271|      error: `write_failed: ${err instanceof Error ? err.message : 'unknown'}`,
   272|      capturedAt,
   273|    };
   274|  }
   275|
   276|  return {
   277|    table,
   278|    ok: true,
   279|    rowCount: result.rows.length,
   280|    hash,
   281|    bytes: json.length,
   282|    status: 200,
   283|    error: null,
   284|    capturedAt,
   285|  };
   286|}
   287|
   288|// ---------------------------------------------------------------------------
   289|// Manifest (append-only ledger)
   290|// ---------------------------------------------------------------------------
   291|
   292|export type ManifestEntry = {
   293|  snapshotId: string;
   294|  timestamp: string;
   295|  tableCount: number;
   296|  totalRows: number;
   297|  totalBytes: number;
   298|  tables: { table: string; rowCount: number; hash: string | null; ok: boolean; error: string | null }[];
   299|  marker: string;
   300|};
   301|
   302|async function appendManifest(entry: ManifestEntry): Promise<void> {
   303|  await ensureVaultDirs();
   304|  try {
   305|    await fs.appendFile(MANIFEST_FILE, JSON.stringify(entry) + '\n', 'utf8');
   306|  } catch {
   307|    // never let manifest failure block a snapshot
   308|  }
   309|}
   310|
   311|export async function readManifest(limit: number = 100): Promise<ManifestEntry[]> {
   312|  try {
   313|    const text = await fs.readFile(MANIFEST_FILE, 'utf8');
   314|    const lines = text.trim().split('\n').filter(Boolean);
   315|    return lines
   316|      .slice(-limit)
   317|      .map((line) => {
   318|        try {
   319|          return JSON.parse(line) as ManifestEntry;
   320|        } catch {
   321|          return null;
   322|        }
   323|      })
   324|      .filter((e): e is ManifestEntry => e !== null)
   325|      .reverse(); // newest first
   326|  } catch {
   327|    return [];
   328|  }
   329|}
   330|
   331|// ---------------------------------------------------------------------------
   332|// State I/O
   333|// ---------------------------------------------------------------------------
   334|
   335|async function ensureVaultDirs(): Promise<void> {
   336|  await fs.mkdir(VAULT_DIR, { recursive: true }).catch(() => {});
   337|  await fs.mkdir(SNAPSHOTS_DIR, { recursive: true }).catch(() => {});
   338|}
   339|
   340|async function readState(): Promise<DataVaultState> {
   341|  try {
   342|    const text = await fs.readFile(STATE_FILE, 'utf8');
   343|    const parsed = JSON.parse(text) as Partial<DataVaultState>;
   344|    return {
   345|      marker: IVX_DATA_VAULT_MARKER,
   346|      config: { ...DEFAULT_CONFIG, ...(parsed.config ?? {}) },
   347|      lastSnapshotAt: parsed.lastSnapshotAt ?? null,
   348|      lastSnapshotId: parsed.lastSnapshotId ?? null,
   349|      totalSnapshots: parsed.totalSnapshots ?? 0,
   350|      nextScheduledRun: parsed.nextScheduledRun ?? null,
   351|    };
   352|  } catch {
   353|    return {
   354|      marker: IVX_DATA_VAULT_MARKER,
   355|      config: DEFAULT_CONFIG,
   356|      lastSnapshotAt: null,
   357|      lastSnapshotId: null,
   358|      totalSnapshots: 0,
   359|      nextScheduledRun: null,
   360|    };
   361|  }
   362|}
   363|
   364|async function writeState(state: DataVaultState): Promise<void> {
   365|  await ensureVaultDirs();
   366|  try {
   367|    await fs.writeFile(STATE_FILE, JSON.stringify(state, null, 2), 'utf8');
   368|  } catch {
   369|    // ignore
   370|  }
   371|}
   372|
   373|export async function getDataVaultState(): Promise<DataVaultState> {
   374|  return readState();
   375|}
   376|
   377|export async function updateDataVaultConfig(patch: Partial<DataVaultConfig>): Promise<DataVaultState> {
   378|  const state = await readState();
   379|  state.config = {
   380|    ...state.config,
   381|    ...patch,
   382|    intervalMs: Math.max(60_000, Number(patch.intervalMs ?? state.config.intervalMs)),
   383|    maxSnapshots: Math.max(0, Math.round(patch.maxSnapshots ?? state.config.maxSnapshots)),
   384|  };
   385|  state.nextScheduledRun = new Date(Date.now() + state.config.intervalMs).toISOString();
   386|  await writeState(state);
   387|  return state;
   388|}
   389|
   390|// ---------------------------------------------------------------------------
   391|// Core snapshot operation
   392|// ---------------------------------------------------------------------------
   393|
   394|export type SnapshotReport = {
   395|  snapshotId: string;
   396|  timestamp: string;
   397|  ok: boolean;
   398|  tableCount: number;
   399|  totalRows: number;
   400|  totalBytes: number;
   401|  tables: TableSnapshotResult[];
   402|  durationMs: number;
   403|  config: DataVaultConfig;
   404|  supabaseConfigured: boolean;
   405|};
   406|
   407|function makeSnapshotId(now: Date): string {
   408|  const stamp = now.toISOString().replace(/[:.]/g, '-');
   409|  const rand = Math.random().toString(36).slice(2, 8);
   410|  return `vault-${stamp}-${rand}`;
   411|}
   412|
   413|export async function runDataVaultSnapshot(): Promise<SnapshotReport> {
   414|  const startedAt = Date.now();
   415|  const now = new Date();
   416|  const snapshotId = makeSnapshotId(now);
   417|  const state = await readState();
   418|
   419|  const supa = resolveSupabase();
   420|  const snapshotDir = path.join(SNAPSHOTS_DIR, snapshotId);
   421|  await ensureVaultDirs();
   422|  await fs.mkdir(snapshotDir, { recursive: true }).catch(() => {});
   423|
   424|  // If Supabase is not configured, record an empty snapshot with the honest reason.
   425|  if (supa.missing.length > 0) {
   426|    const report: SnapshotReport = {
   427|      snapshotId,
   428|      timestamp: now.toISOString(),
   429|      ok: false,
   430|      tableCount: 0,
   431|      totalRows: 0,
   432|      totalBytes: 0,
   433|      tables: state.config.tables.map((table) => ({
   434|        table,
   435|        ok: false,
   436|        rowCount: 0,
   437|        hash: null,
   438|        bytes: 0,
   439|        status: 0,
   440|        error: `not_configured: ${supa.missing.join(', ')}`,
   441|        capturedAt: now.toISOString(),
   442|      })),
   443|      durationMs: Date.now() - startedAt,
   444|      config: state.config,
   445|      supabaseConfigured: false,
   446|    };
   447|
   448|    // Write meta.json with the failure reason
   449|    await fs.writeFile(
   450|      path.join(snapshotDir, 'meta.json'),
   451|      JSON.stringify(report, null, 2),
   452|      'utf8',
   453|    ).catch(() => {});
   454|
   455|    return report;
   456|  }
   457|
   458|  // Snapshot all configured tables in parallel batches of 5.
   459|  const tables = state.config.tables;
   460|  const results: TableSnapshotResult[] = [];
   461|  const batchSize = 5;
   462|
   463|  for (let i = 0; i < tables.length; i += batchSize) {
   464|    const batch = tables.slice(i, i + batchSize);
   465|    const batchResults = await Promise.all(
   466|      batch.map((table) => snapshotOneTable(supa.url, supa.key, table, snapshotDir)),
   467|    );
   468|    results.push(...batchResults);
   469|  }
   470|
   471|  const totalRows = results.reduce((sum, r) => sum + r.rowCount, 0);
   472|  const totalBytes = results.reduce((sum, r) => sum + r.bytes, 0);
   473|  const okCount = results.filter((r) => r.ok).length;
   474|
   475|  const report: SnapshotReport = {
   476|    snapshotId,
   477|    timestamp: now.toISOString(),
   478|    ok: okCount > 0,
   479|    tableCount: results.length,
   480|    totalRows,
   481|    totalBytes,
   482|    tables: results,
   483|    durationMs: Date.now() - startedAt,
   484|    config: state.config,
   485|    supabaseConfigured: true,
   486|  };
   487|
   488|  // Write meta.json
   489|  await fs.writeFile(
   490|    path.join(snapshotDir, 'meta.json'),
   491|    JSON.stringify(report, null, 2),
   492|    'utf8',
   493|  ).catch(() => {});
   494|
   495|  // Append to manifest
   496|  const manifestEntry: ManifestEntry = {
   497|    snapshotId,
   498|    timestamp: now.toISOString(),
   499|    tableCount: results.length,
   500|    totalRows,
   501|    totalBytes,
   502|    tables: results.map((r) => ({
   503|      table: r.table,
   504|      rowCount: r.rowCount,
   505|      hash: r.hash,
   506|      ok: r.ok,
   507|      error: r.error,
   508|    })),
   509|    marker: IVX_DATA_VAULT_MARKER,
   510|  };
   511|  await appendManifest(manifestEntry);
   512|
   513|  // Update state
   514|  state.lastSnapshotAt = now.toISOString();
   515|  state.lastSnapshotId = snapshotId;
   516|  state.totalSnapshots += 1;
   517|  state.nextScheduledRun = new Date(Date.now() + state.config.intervalMs).toISOString();
   518|  await writeState(state);
   519|
   520|  // Enforce retention (keep ALL if maxSnapshots is 0)
   521|  if (state.config.maxSnapshots > 0) {
   522|    await enforceRetention(state.config.maxSnapshots);
   523|  }
   524|
   525|  console.log(`[IVXDataVault] snapshot ${snapshotId} complete: ${okCount}/${results.length} tables, ${totalRows} rows, ${(totalBytes / 1024).toFixed(1)}KB`);
   526|
   527|  return report;
   528|}
   529|
   530|// ---------------------------------------------------------------------------
   531|// Retention enforcement
   532|// ---------------------------------------------------------------------------
   533|
   534|async function enforceRetention(keepCount: number): Promise<void> {
   535|  try {
   536|    const entries = await fs.readdir(SNAPSHOTS_DIR, { withFileTypes: true });
   537|    const dirs = entries.filter((e) => e.isDirectory()).map((e) => e.name).sort();
   538|    if (dirs.length <= keepCount) return;
   539|
   540|    const toRemove = dirs.slice(0, dirs.length - keepCount);
   541|    for (const dir of toRemove) {
   542|      await fs.rm(path.join(SNAPSHOTS_DIR, dir), { recursive: true, force: true }).catch(() => {});
   543|      console.log(`[IVXDataVault] removed old snapshot ${dir} (retention=${keepCount})`);
   544|    }
   545|  } catch {
   546|    // ignore
   547|  }
   548|}
