   702|
   703|  for (const table of tablesToRestore) {
   704|    const { rows, ok, error } = await readSnapshotTable(snapshotId, table);
   705|    if (!ok || rows.length === 0) {
   706|      results.push({ table, ok: false, rowsAttempted: rows.length, rowsUpserted: 0, error: error ?? 'no_rows' });
