   708|    }
   709|
   710|    try {
   711|      // Upsert via Supabase REST API. We use the Prefer: resolution=merge-duplicates
   712|      // header so existing rows (by PK) are updated, new rows are inserted.
   713|      const res = await fetch(`${supa.url}/rest/v1/${table}`, {
   714|        method: 'POST',
   715|        headers: {
   716|          apikey: supa.key,
   717|          Authorization: `Bearer ${supa.key}`,
   718|          'Content-Type': 'application/json',
   719|          Prefer: 'return=minimal,resolution=merge-duplicates',
   720|        },
   721|        body: JSON.stringify(rows),
   722|      });
