   735|          table,
   736|          ok: true,
   737|          rowsAttempted: rows.length,
   738|          rowsUpserted: rows.length,
   739|          error: null,
   740|        });
   741|      }
   742|    } catch (err) {
   743|      results.push({
   744|        table,
   745|        ok: false,
   746|        rowsAttempted: rows.length,
   747|        rowsUpserted: 0,
