   781|/**
   782| * Compare the latest vault snapshot against live Supabase row counts. If a
   783| * table has significantly fewer rows in production than in the snapshot, flag
   784| * it as potential data loss. This runs automatically before every scheduled
   785| * snapshot and can be triggered manually.
   786| */
   787|export async function detectDataLoss(): Promise<DataLossAlert> {
   788|  const checkedAt = new Date().toISOString();
   789|  const state = await readState();
   790|
   791|  if (!state.lastSnapshotId) {
   792|    return {
   793|      detected: false,
   794|      severity: 'none',
   795|      tablesAffected: [],
   796|      lastSnapshotId: null,
   797|      lastSnapshotAt: null,
   798|      checkedAt,
   799|    };
   800|  }
   801|
   802|  const snapshot = await readSnapshot(state.lastSnapshotId);
   803|  if (!snapshot) {
   804|    return {
   805|      detected: false,
   806|      severity: 'none',
   807|      tablesAffected: [],
   808|      lastSnapshotId: state.lastSnapshotId,
   809|      lastSnapshotAt: state.lastSnapshotAt,
   810|      checkedAt,
   811|    };
   812|  }
   813|
   814|  const supa = resolveSupabase();
   815|  if (supa.missing.length > 0) {
   816|    return {
   817|      detected: false,
   818|      severity: 'none',
   819|      tablesAffected: [],
   820|      lastSnapshotId: state.lastSnapshotId,
   821|      lastSnapshotAt: state.lastSnapshotAt,
   822|      checkedAt,
   823|    };
   824|  }
   825|
   826|  const headers = {
   827|    apikey: supa.key,
   828|    Authorization: `Bearer ${supa.key}`,
   829|    Accept: 'application/json',
   830|  };
   831|
   832|  const alerts: DataLossAlert['tablesAffected'] = [];
   833|
   834|  for (const tableResult of snapshot.tables) {
   835|    if (!tableResult.ok || tableResult.rowCount === 0) continue;
   836|
   837|    try {
   838|      const res = await fetch(`${supa.url}/rest/v1/${tableResult.table}?select=id`, {
   839|        method: 'HEAD',
   840|        headers: { ...headers, Prefer: 'count=exact', Range: '0-0' },
   841|      });
   842|      if (!res.ok) continue;
   843|      const cr = res.headers.get('content-range');
   844|      const liveCount = cr ? parseInt(cr.split('/').pop() || '*', 10) : null;
   845|      if (liveCount === null || !Number.isFinite(liveCount)) continue;
   846|
   847|      if (liveCount < tableResult.rowCount) {
   848|        const rowsLost = tableResult.rowCount - liveCount;
   849|        alerts.push({
   850|          table: tableResult.table,
   851|          snapshotRows: tableResult.rowCount,
   852|          liveRows: liveCount,
   853|          rowsLost,
   854|        });
   855|      }
   856|    } catch {
   857|      // skip unreachable tables
   858|    }
   859|  }
   860|
   861|  const severity = alerts.some((a) => a.rowsLost >= 50) ? 'critical' : alerts.length > 0 ? 'warning' : 'none';
   862|
   863|  if (severity !== 'none') {
   864|    console.warn(`[IVXDataVault] DATA LOSS DETECTED — severity=${severity}`, alerts);
   865|  }
   866|
   867|  return {
   868|    detected: alerts.length > 0,
   869|    severity,
   870|    tablesAffected: alerts,
   871|    lastSnapshotId: state.lastSnapshotId,
   872|    lastSnapshotAt: state.lastSnapshotAt,
   873|    checkedAt,
   874|  };
